        ("Epigenetic Age", "The biological age of cells as measured by DNA methylation patterns — can differ from chronological age and is influenced by lifestyle, environment, disease, and interventions, representing the cumulative dysregulation of gene expression programs that maintain cellular identity and function", False),
        ("Mitochondrial Function", "The efficiency of cellular energy production by mitochondria — declines with age as mitochondrial DNA accumulates mutations and the organelles become less efficient, producing more ROS waste while generating less ATP energy", False),
